 Worker,
 isMainThread,
 parentPort,
 workerData,
} from 'node:worker_threads';

if (!isMainThread) {
 const { parse } = await import('some-js-parsing-library');
 const script = workerData;
 parentPort.postMessage(parse(script));
}

