http.createServer((req, res) => {
 asyncLocalStorage.run(idSeq++, () => {
 logWithId('start');
 // Imagine any chain of async operations here
 setImmediate(() => {
 logWithId('finish');
 res.end();
 });
 });
}).listen(8080);

http.get('http://localhost:8080');
http.get('http://localhost:8080');
